// src/Login.js
import React, { useState } from 'react';
import axios from 'axios';

function Login({ onLogin }) {
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [mensagem, setMensagem] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('/api/login', { usuario, senha });
      onLogin(res.data);
    } catch (error) {
      setMensagem('Usuário ou senha inválidos!');
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-100">
      {/* --- Lado da ilustração (esconde no mobile) --- */}
      <div
        className="hidden md:block md:w-1/2 bg-cover bg-center"
        style={{
          backgroundImage: "url('/login-image.jpg')"
        }}
      />

      {/* --- Lado do formulário --- */}
      <div className="flex w-full md:w-1/2 items-center justify-center p-6">
        <form
          onSubmit={handleSubmit}
          className="w-full max-w-sm bg-white rounded-2xl shadow-lg p-8 space-y-6"
        >
          <h2 className="text-center text-3xl font-bold text-gray-800">
            PoliUB
            Atendimentos
          </h2>
          <p className="text-center text-gray-600">
            Faça login na sua conta
          </p>

          <input
            type="text"
            placeholder="Usuário"
            value={usuario}
            onChange={(e) => setUsuario(e.target.value)}
            required
            className="w-full border border-gray-300 rounded-full px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-300"
          />

          <input
            type="password"
            placeholder="Senha"
            value={senha}
            onChange={(e) => setSenha(e.target.value)}
            required
            className="w-full border border-gray-300 rounded-full px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-300"
          />

          <button
            type="submit"
            className="w-full bg-[#3172C0] hover:bg-[#255a9a] text-white font-semibold py-2 rounded-full transition"
          >
            Entrar
          </button>

          {mensagem && (
            <p className="text-center text-red-600">{mensagem}</p>
          )}
        </form>
      </div>
    </div>
  );
}

export default Login;
